X * more details.
X * 
X * You should have received a copy of the GNU General Public License along with
X * this program; if not, write to the Free Software Foundation, Inc., 675
X * Mass Ave, Cambridge, MA 02139, USA.
X * 
X * linux_audio.c
X * 
X * Functions to play sound on the VoxWare audio driver (Linux or FreeBSD)
X * 
X */
X
#include <unistd.h>
#include <fcntl.h>
#include <errno.h>
X
#ifdef linux
#include <sys/ioctl.h>		/* new with 1.2.0? Didn't need this under
X				 * 1.1.64 */
#include <linux/soundcard.h>
#endif
X
#ifdef __FreeBSD__
#include <stdio.h>
#include <machine/soundcard.h>
#endif
X
#include "config.h"
#include "output.h"
#include "controls.h"
X
static int      open_output(void);	/* 0=success, 1=warning, -1=fatal
X					 * error */
static void     close_output(void);
static void     output_data(int32 * buf, int32 count);
static void     flush_output(void);
static void     purge_output(void);
X
/* export the playback mode */
X
#define dpm linux_play_mode
X
PlayMode        dpm = {
X    DEFAULT_RATE, PE_16BIT | PE_SIGNED,
X    -1,
X    {0},			/* default: get all the buffer fragments you
X				 * can */
X    "Linux dsp device", 'd',
X    "/dev/dsp",
X    open_output,
X    close_output,
X    output_data,
X    flush_output,
X    purge_output
};
X
X
/*************************************************************************/
/*
X * We currently only honor the PE_MONO bit, the sample rate, and the number
X * of buffer fragments. We try 16-bit signed data first, and then 8-bit
X * unsigned if it fails. If you have a sound device that can't handle either,
X * let me know.
X */
X
static int 
open_output(void)
{
X    int             fd, tmp, i, warnings = 0;
X
X    /* Open the audio device */
X    fd = open(dpm.name, O_RDWR /* | O_NDELAY */);
X    if (fd < 0) {
X	ctl->cmsg(CMSG_ERROR, VERB_NORMAL, "%s: %s",
X		  dpm.name, sys_errlist[errno]);
X	return -1;
X    }
X    /* They can't mean these */
X    dpm.encoding &= ~(PE_ULAW | PE_BYTESWAP);
X
X
X    /*
X     * Set sample width to whichever the user wants. If it fails, try the
X     * other one.
X     */
X
X    i = tmp = (dpm.encoding & PE_16BIT) ? 16 : 8;
X    if (dpm.encoding & PE_16BIT) {
X        int fmt = AFMT_S16_LE ;
X
X	if (ioctl(fd, SNDCTL_DSP_SETFMT, &fmt) < 0 || fmt != AFMT_S16_LE) {
X	    fmt = AFMT_U8 ;
X	    if (ioctl(fd, SNDCTL_DSP_SETFMT, &fmt) < 0 || fmt != AFMT_U8) {
X		ctl->cmsg(CMSG_ERROR, VERB_NORMAL,
X		      "%s doesn't support 16- or 8-bit sample width",
X		      dpm.name);
X		close(fd);
X		return -1;
X	    }
X	    ctl->cmsg(CMSG_WARNING, VERB_VERBOSE,
X		  "Sample width adjusted to %d bits", tmp);
X	    dpm.encoding ^= PE_16BIT;
X	    warnings = 1;
X	}
X    }
X    if (dpm.encoding & PE_16BIT)
X	dpm.encoding |= PE_SIGNED;
X    else
X	dpm.encoding &= ~PE_SIGNED;
X
X
X    /*
X     * Try stereo or mono, whichever the user wants. If it fails, try the
X     * other.
X     */
X
X    i = tmp = (dpm.encoding & PE_MONO) ? 0 : 1;
X    if ((ioctl(fd, SNDCTL_DSP_STEREO, &tmp) < 0) || tmp != i) {
X	i = tmp = (dpm.encoding & PE_MONO) ? 1 : 0;
X
X	if ((ioctl(fd, SNDCTL_DSP_STEREO, &tmp) < 0) || tmp != i) {
X	    ctl->cmsg(CMSG_ERROR, VERB_NORMAL,
X		      "%s doesn't support mono or stereo samples",
X		      dpm.name);
X	    close(fd);
X	    return -1;
X	}
X	if (tmp == 0)
X	    dpm.encoding |= PE_MONO;
X	else
X	    dpm.encoding &= ~PE_MONO;
X	ctl->cmsg(CMSG_WARNING, VERB_VERBOSE, "Sound adjusted to %sphonic",
X		  (tmp == 0) ? "mono" : "stereo");
X	warnings = 1;
X    }
X    /* Set the sample rate */
X
X    tmp = dpm.rate;
X    if (ioctl(fd, SNDCTL_DSP_SPEED, &tmp) < 0) {
X	ctl->cmsg(CMSG_ERROR, VERB_NORMAL,
X		  "%s doesn't support a %d Hz sample rate",
X		  dpm.name, dpm.rate);
X	close(fd);
X	return -1;
X    }
X    if (tmp != dpm.rate) {
X	dpm.rate = tmp;
X	ctl->cmsg(CMSG_WARNING, VERB_VERBOSE,
X		  "Output rate adjusted to %d Hz", dpm.rate);
X	warnings = 1;
X    }
X    /* Older VoxWare drivers don't have buffer fragment capabilities */
#ifdef SNDCTL_DSP_SETFRAGMENT
X    /* Set buffer fragments (in extra_param[0]) */
X
X    tmp = 2+ AUDIO_BUFFER_BITS ;
X    if (!(dpm.encoding & PE_MONO))
X	tmp++;
X    if (dpm.encoding & PE_16BIT)
X	tmp++;
X    tmp |= (dpm.extra_param[0] << 16);
X    i = tmp;
X    if (ioctl(fd, SNDCTL_DSP_SETFRAGMENT, &tmp) < 0) {
X	ctl->cmsg(CMSG_WARNING, VERB_NORMAL,
X	 "%s doesn't support %d-byte buffer fragments", dpm.name, (1 << i));
X	/*
X	 * It should still work in some fashion. We should use a secondary
X	 * buffer anyway -- 64k isn't enough.
X	 */
X	warnings = 1;
X    }
#else
X    if (dpm.extra_param[0]) {
X	ctl->cmsg(CMSG_WARNING, VERB_NORMAL,
X		  "%s doesn't support buffer fragments", dpm.name);
X	warnings = 1;
X    }
#endif
X
X    dpm.fd = fd;
X
X    return warnings;
}
X
static void 
output_data(int32 * buf, int32 count)
{
X    char *p;
X    int res, l;
X
X    if (!(dpm.encoding & PE_MONO))
X	count *= 2;		/* Stereo samples */
X
X    if (dpm.encoding & PE_16BIT) {
X	/* Convert data to signed 16-bit PCM */
X	s32tos16(buf, count);
X	res = count*2;
X    } else {
X	/* Convert to 8-bit unsigned and write out. */
X	s32tou8(buf, count);
X	res = count ;
X    }
X    for (p = buf ; res > 0 ; res -= l ) {
X	l = write(dpm.fd, p, res);
X	if (l < 0) return ;
X	p += l ;
X    }
}
X
static void 
close_output(void)
{
X    close(dpm.fd);
}
X
static void 
flush_output(void)
{
X    ioctl(dpm.fd, SNDCTL_DSP_SYNC);
}
X
static void 
purge_output(void)
{
X    ioctl(dpm.fd, SNDCTL_DSP_RESET);
}
